      function CF_267Formula return Char is
	
	v_calc_date		 	 DATE;
	----17/12/2008----------------
	v_denominator		 NUMBER;
	CURSOR cur_age_reduction_denom IS
	SELECT denominator
	FROM PEN_AGE_REDUCTION_DENOM
	WHERE VALIDITY_DATE <= v_calc_date--:P_FACTITIOUS_DATE
	ORDER BY VALIDITY_DATE DESC;
	-------------------------------

BEGIN
	
/*  IF :P_FACTITIOUS_DATE >= '1/1/2003' THEN 
  	RETURN ('/267');
  ELSE 
  	RETURN ('/200');
  END IF; */	

	v_calc_date := :P_FACTITIOUS_DATE;
  IF :P_ACC_START_DATE < :P_FACTITIOUS_DATE THEN
     v_calc_date := :P_ACC_START_DATE;
  END IF;

	----17/12/2008---
	OPEN cur_age_reduction_denom;
	FETCH cur_age_reduction_denom
	INTO v_denominator;
	CLOSE cur_age_reduction_denom;
				
	RETURN ('/'||v_denominator);				
	-----------------			
	
end;

