      function CF_12Formula return Char is
cursor cur_pen_account_rep is
select 
account_no, 
total_days, 
total_days_h, 
flg_kind, 
pen_class,
amnt1,
amnt2,
amnt1+amnt2 tot_amnt,
perc,
amnt3,
LOWEST_CALC_DAYS,
perc_v
from pen_account_rep
where account_no=:P_ACC_ACCOUNT_NO;

v_cur_pen_account_rep  cur_pen_account_rep%rowtype;

my_total_days1  number;
my_total_days2  number;
my_total_days_h number;
my_text1				varchar2(512);
my_text2				varchar2(512);
my_text3				varchar2(512);
my_text4				varchar2(512);

begin
	
open 	cur_pen_account_rep;
fetch cur_pen_account_rep
into  v_cur_pen_account_rep;
close cur_pen_account_rep;

if v_cur_pen_account_rep.total_days<300 then                       
my_total_days1	:=v_cur_pen_account_rep.total_days;
else
--my_total_days1	:=floor(v_cur_pen_account_rep.total_days/300)*300;
my_total_days1	:=v_cur_pen_account_rep.total_days;
end if;	
--my_total_days2	:=floor((v_cur_pen_account_rep.total_days-10500)/300)*300;
my_total_days2	:=(v_cur_pen_account_rep.total_days-10500);
my_total_days_h	:=v_cur_pen_account_rep.total_days_h;



if v_cur_pen_account_rep.flg_kind='1' then
	 	my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||round(v_cur_pen_account_rep.pen_class,2)||' *  20% * ( '||my_total_days1||'/10500 '||' ) '||' = '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt1,2),'999G999G990D90'));
elsif v_cur_pen_account_rep.flg_kind='2' then
		my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||'0.02 * '||'10500/300* '||round(v_cur_pen_account_rep.pen_class,2)||' + '||'0.03* '||my_total_days2||'/300 '||'*'||round(v_cur_pen_account_rep.pen_class,2)||'='||Ltrim(to_char(round(v_cur_pen_account_rep.amnt1,2),'999G999G990D90'));
else
		my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||round(v_cur_pen_account_rep.pen_class,2)||' *  20% * ( '||my_total_days1||'/10500 '||' ) '||' = '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt1,2),'999G999G990D90'));
end if;

if v_cur_pen_account_rep.total_days_h<>0 AND NVL(v_cur_pen_account_rep.amnt2,0) > 0 then
	 my_text2:='TΟ ΠΟΣΟ ΤΗΣ ΠΡΟΣΑΥΞΗΣΗΣ ΒΑΡΕΩΝ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ : '||'0.2 * '||round(v_cur_pen_account_rep.pen_class,2)||' * 0.2 * '||my_total_days_h||'/10500 '||'='||Ltrim(to_char(round(v_cur_pen_account_rep.amnt2,2),'999G999G990D90'));
	 my_text1:=my_text1||chr(10)||my_text2;
   IF	NVL(v_cur_pen_account_rep.amnt1,0) + NVL(v_cur_pen_account_rep.amnt2,0) != NVL(v_cur_pen_account_rep.amnt3,0) THEN
		my_text3:='ΤΟ ΣΥΝΟΛΙΚΟ Β.Π. ΜΕ ΤΗΝ EΤΗΣΙΑ ΑΥΞΗΣΗ '||v_cur_pen_account_rep.perc_v||' ΔΙΑΜΟΡΦΩΝΕΤΑΙ ΣΕ: '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt3,2),'999G999G990D90'));
		my_text1:=my_text1||chr(10)||my_text3;
   ELSE
		my_text3:='ΤΟ ΣΥΝΟΛΙΚΟ Β.Π. (ΔΕΝ ΕΧΕΙ ΔΟΘΕΙ ΕΤΗΣΙΑ ΑΥΞΗΣΗ) ΔΙΑΜΟΡΦΩΝΕΤΑΙ ΣΕ: '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt3,2),'999G999G990D90'));
		my_text1:=my_text1||chr(10)||my_text3;   	
	 END IF;
else
	 IF	NVL(v_cur_pen_account_rep.amnt1,0) + NVL(v_cur_pen_account_rep.amnt2,0) != NVL(v_cur_pen_account_rep.amnt3,0) THEN
		my_text3:='ΤΟ ΟΠΟΙΟ ΜΕ ΤΗΝ EΤΗΣΙΑ ΑΥΞΗΣΗ '||v_cur_pen_account_rep.perc_v||' ΔΙΑΜΟΡΦΩΝΕΤΑΙ ΣΕ: '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt3,2),'999G999G990D90'));
		my_text1:=my_text1||chr(10)||my_text3;
	 ELSE
		my_text3:='ΣΤΟ ΟΠΟΙΟ ΔΕΝ ΕΧΕΙ ΔΟΘΕΙ ΕΤΗΣΙΑ ΑΥΞΗΣΗ ';
		my_text1:=my_text1||chr(10)||my_text3;	 	
	 END IF;
end if;	 
	 
	/*my_text3:='ΤΟ ΟΠΟΙΟ ΜΕ ΤΗΝ EΤΗΣΙΑ ΑΥΞΗΣΗ '||v_cur_pen_account_rep.perc*100||'ΔΙΑΜΟΡΦΩΝΕΤΑΙ ΣΕ: '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt3,2),'999G999G990D90'));
		my_text1:=my_text1||chr(10)||my_text3;*/

if v_cur_pen_account_rep.LOWEST_CALC_DAYS is not null then
	 my_text4:='ΤO ΚΑΤΩΤΑΤΟ ΠΟΣΟ ΥΠΟΛΟΓΙΣΤΗΚΕ ΟΠΩΣ ΤΟ ΒΑΣΙΚΟ, ΧΡΗΣΙΜΟΠΟΙΩΝΤΑΣ '||v_cur_pen_account_rep.LOWEST_CALC_DAYS||' ΗΜΕΡΕΣ ΕΡΓΑΣΙΑΣ';
	 my_text1:=my_text1||chr(10)||my_text4;
end if;


return my_text1;
	
	
  
end;

